  1	import {
  2	  DataState,
  3	  PipelineExampleNames,
  4	  pipelineTestData,
  5	} from '../../../../test-data/pipeline-data';
  6	import { PipelineRunKind } from '../../../../types';
  7	import {
  8	  ErrorDetailsWithLogName,
  9	  ErrorDetailsWithStaticLog,
 10	} from '../../../logs/log-snippet-types';
 11	import { getTRLogSnippet } from '../../taskRunLogSnippet';
 12	
 13	const taskRunMock =
 14	  pipelineTestData[PipelineExampleNames.WORKSPACE_PIPELINE].taskRuns[0];
 15	const plrWithFailedTaskRun =
 16	  pipelineTestData[PipelineExampleNames.BROKEN_MOCK_APP].pipelineRuns[
 17	    DataState.FAILED1
 18	  ];
 19	const plrWithTaskRunTimeoutError =
 20	  pipelineTestData[PipelineExampleNames.BROKEN_MOCK_APP].pipelineRuns[
 21	    DataState.FAILED2
 22	  ];
 23	
 24	const getFailedTaskRunStatus = (plr: PipelineRunKind) => {
 25	  const [taskRunStatus] = Object.values(plr.status.taskRuns).filter((tr) =>
 26	    tr?.status?.conditions?.find(
 27	      (condition) =>
 28	        condition.type === 'Succeeded' && condition.status === 'False',
 29	    ),
 30	  );
 31	  return taskRunStatus?.status;
 32	};
 33	
 34	describe('TaskRunLogSnippet test', () => {
 35	  it('should return null for successful TaskRun', () => {
 36	    const msg = getTRLogSnippet(taskRunMock);
 37	    expect(msg).toEqual(null);
 38	  });
 39	
 40	  it('should return null if TaskRun value is null', () => {
 41	    const msg = getTRLogSnippet(null);
 42	    expect(msg).toEqual(null);
 43	  });
 44	
 45	  it('should return a Log message for failed TaskRun with task container', () => {
 46	    const taskRunWithContainer = {
 47	      ...taskRunMock,
 48	      status: { ...getFailedTaskRunStatus(plrWithFailedTaskRun) },
 49	    };
 50	    const { title, containerName, podName } = getTRLogSnippet(
 51	      taskRunWithContainer,
 52	    ) as ErrorDetailsWithLogName;
 53	    expect(title).toEqual(
 54	      'Failure on task {{taskName}} - check logs for details.',
 55	    );
 56	    expect(containerName).toEqual('step-build');
 57	    expect(podName).toEqual(
 58	      'broken-app-pipeline-j2nxzm-x-compile-8mq2h-pod-b9gsg',
 59	    );
 60	  });
 61	
 62	  it('should return a Log message for TaskRun with TaskRunTimeout reason', () => {
 63	    const timeOutTaskRun = {
 64	      ...taskRunMock,
 65	      status: { ...getFailedTaskRunStatus(plrWithTaskRunTimeoutError) },
 66	    };
 67	    const { title, staticMessage } = getTRLogSnippet(
 68	      timeOutTaskRun,
 69	    ) as ErrorDetailsWithStaticLog;
 70	    expect(title).toEqual(
 71	      'Failure on task {{taskName}} - check logs for details.',
 72	    );
 73	    expect(staticMessage).toEqual(
 74	      'TaskRun "fetch-and-print-recipe-test-fetch-the-recipe-5pb9p" failed to finish within "5s"',
 75	    );
 76	  });
 77	
 78	  it('should return a static message', () => {
 79	    const failedTaskRun = {
 80	      ...taskRunMock,
 81	      status: { ...getFailedTaskRunStatus(plrWithTaskRunTimeoutError) },
 82	    };
 83	    const { title, staticMessage } = getTRLogSnippet({
 84	      ...taskRunMock,
 85	      status: {
 86	        ...failedTaskRun.status,
 87	        conditions: [
 88	          {
 89	            ...failedTaskRun.status.conditions[0],
 90	            status: 'False',
 91	            message: '',
 92	          },
 93	        ],
 94	      },
 95	    }) as ErrorDetailsWithStaticLog;
 96	    expect(title).toEqual(
 97	      'Failure on task {{taskName}} - check logs for details.',
 98	    );
 99	    expect(staticMessage).toEqual('Unknown failure condition');
100	  });
101	});

